# Computes a(n) for n >= 1 by simulating the process
def get_next_x(x):
    if x % 2 == 1 and x > 1:
        return (x - 1) // 2
    if x % 4 == 0 and x > 4:
        return (x - 4) // 4
    return None
def a(n):
    curr, count = n, 1
    while True:
        nxt = get_next_x(curr)
        if nxt is None:
            break
        curr, count = nxt, count + 1
    return count
print([a(n) for n in range(1, 101)])

